import { GameStat } from "../../objects/game-stat";

interface GameStatComponentProps{
    gameStats : GameStat[]    
}

const GameStatTable = (gameStatProps : GameStatComponentProps) => {      

    return(
        <>                       
        <div className="row">            
            <div>
                <table className="table table-hover table-condensed table-responsive">
                    <thead>
                        <tr>
                            <th>Apps</th>  
                            <th>Player</th>  
                            <th>Goals</th>
                            <th>Assists</th>
                            <th>GSOs</th>
                            <th>Shots</th>
                            <th>Tackles</th>                            
                        </tr>
                    </thead>
                    <tbody>
                        {gameStatProps.gameStats.map(f => 
                            <>
                            <tr>
                                <td>{f.apps}</td>
                                <td>{f.playerName}</td>
                                <td>{f.goals}</td>
                                <td>{f.assists}</td>
                                <td>{f.gso}</td>
                                <td>{f.shots}</td>
                                <td>{f.tackles}</td>
                                </tr>
                            </>
                        )}
                    </tbody>
                </table>                          
            </div>
        </div>                
        </>
    );
}
export default GameStatTable;


